import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Login from './components/Login';
import { authService } from './services/api';

// Componente de Crear Oferta
const CrearOferta = () => {
  return (
    <div style={styles.formContainer}>
      <h2 style={styles.formTitle}>Crear Nueva Oferta</h2>
      <form style={styles.form}>
        <div style={styles.formGroup}>
          <label style={styles.label}>Programa de Formación:</label>
          <select style={styles.select}>
            <option>EXPRESION ORAL Y CORPORAL</option>
            <option>OTRO PROGRAMA</option>
          </select>
        </div>

        <div style={styles.formGroup}>
          <label style={styles.label}>Modalidad:</label>
          <select style={styles.select}>
            <option>Presencial</option>
            <option>Virtual</option>
          </select>
        </div>

        <div style={styles.formRow}>
          <div style={styles.formGroupHalf}>
            <label style={styles.label}>Fecha Inicio:</label>
            <input type="date" style={styles.input} />
          </div>
          <div style={styles.formGroupHalf}>
            <label style={styles.label}>Fecha Fin:</label>
            <input type="date" style={styles.input} />
          </div>
        </div>

        <div style={styles.formGroup}>
          <label style={styles.label}>Cupo Máximo:</label>
          <input type="number" style={styles.input} placeholder="30" />
        </div>

        <div style={styles.formGroup}>
          <label style={styles.label}>Municipio:</label>
          <select style={styles.select}>
            <option>Popayán</option>
          </select>
        </div>

        <div style={styles.formGroup}>
          <label style={styles.label}>Empresa Solicitante:</label>
          <input type="text" style={styles.input} placeholder="Nombre de la empresa" />
        </div>

        <div style={styles.formGroup}>
          <label style={styles.label}>NIT:</label>
          <input type="text" style={styles.input} placeholder="123456789-0" />
        </div>

        <div style={styles.formRow}>
          <div style={styles.formGroupHalf}>
            <label style={styles.label}>Hora Inicio:</label>
            <input type="time" style={styles.input} defaultValue="08:00" />
          </div>
          <div style={styles.formGroupHalf}>
            <label style={styles.label}>Hora Fin:</label>
            <input type="time" style={styles.input} defaultValue="12:00" />
          </div>
        </div>

        <div style={styles.formGroup}>
          <label style={styles.label}>Días:</label>
          <div style={styles.checkboxGroup}>
            <label style={styles.checkboxLabel}>
              <input type="checkbox" /> Lunes
            </label>
            <label style={styles.checkboxLabel}>
              <input type="checkbox" /> Martes
            </label>
            <label style={styles.checkboxLabel}>
              <input type="checkbox" /> Miércoles
            </label>
            <label style={styles.checkboxLabel}>
              <input type="checkbox" /> Jueves
            </label>
            <label style={styles.checkboxLabel}>
              <input type="checkbox" /> Viernes
            </label>
          </div>
        </div>

        <button type="submit" style={styles.submitButton}>
          Guardar Oferta
        </button>
      </form>
    </div>
  );
};

// Componente de Solicitar Oferta
const SolicitarOferta = () => {
  return (
    <div style={styles.formContainer}>
      <h2 style={styles.formTitle}>Solicitar Oferta</h2>
      <form style={styles.form}>
        <div style={styles.formGroup}>
          <label style={styles.label}>Tipo de Solicitud:</label>
          <select style={styles.select}>
            <option>Nueva oferta</option>
            <option>Modificación de oferta</option>
            <option>Cancelación</option>
          </select>
        </div>

        <div style={styles.formGroup}>
          <label style={styles.label}>Descripción de la solicitud:</label>
          <textarea 
            style={styles.textarea} 
            rows="5" 
            placeholder="Describa detalladamente su solicitud..."
          />
        </div>

        <div style={styles.formGroup}>
          <label style={styles.label}>Justificación:</label>
          <textarea 
            style={styles.textarea} 
            rows="3" 
            placeholder="Justifique su solicitud..."
          />
        </div>

        <div style={styles.formGroup}>
          <label style={styles.label}>Documentos adjuntos:</label>
          <input type="file" style={styles.fileInput} multiple />
        </div>

        <button type="submit" style={styles.submitButton}>
          Enviar Solicitud
        </button>
      </form>
    </div>
  );
};

// Dashboard con dos columnas
const Dashboard = () => {
  const [vistaActiva, setVistaActiva] = useState('crear'); // 'crear' o 'solicitar'
  const user = authService.getCurrentUser();
  
  const handleLogout = () => {
    authService.logout();
    window.location.href = '/login';
  };

  return (
    <div style={styles.dashboard}>
      {/* Header */}
      <div style={styles.header}>
        <h1 style={styles.headerTitle}>Gestionytics - Panel de Control</h1>
        <div style={styles.userInfo}>
          <span style={styles.userName}>{user?.nombreUsuario}</span>
          <button onClick={handleLogout} style={styles.logoutButton}>
            Cerrar Sesión
          </button>
        </div>
      </div>

      {/* Contenedor de dos columnas */}
      <div style={styles.mainContainer}>
        {/* Columna Izquierda - Menú */}
        <div style={styles.sidebar}>
          <div style={styles.sidebarHeader}>
            <h3 style={styles.sidebarTitle}>Menú Principal</h3>
          </div>
          
          <button 
            onClick={() => setVistaActiva('crear')}
            style={{
              ...styles.menuButton,
              ...(vistaActiva === 'crear' ? styles.menuButtonActive : {})
            }}
          >
            ➕ Crear Oferta
          </button>
          
          <button 
            onClick={() => setVistaActiva('solicitar')}
            style={{
              ...styles.menuButton,
              ...(vistaActiva === 'solicitar' ? styles.menuButtonActive : {})
            }}
          >
            📝 Solicitar Oferta
          </button>

          <div style={styles.coordinadorInfo}>
            <p style={styles.coordinadorLabel}>Coordinador Asignado:</p>
            <p style={styles.coordinadorNombre}>{user?.coordinadorAsignado?.nombre}</p>
          </div>
        </div>

        {/* Columna Derecha - Contenido */}
        <div style={styles.content}>
          {vistaActiva === 'crear' ? <CrearOferta /> : <SolicitarOferta />}
        </div>
      </div>
    </div>
  );
};

const styles = {
  dashboard: {
    minHeight: '100vh',
    backgroundColor: '#f0f2f5',
    fontFamily: 'Arial, sans-serif'
  },
  header: {
    backgroundColor: '#2c3e50',
    color: 'white',
    padding: '15px 30px',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    boxShadow: '0 2px 5px rgba(0,0,0,0.1)'
  },
  headerTitle: {
    margin: 0,
    fontSize: '24px'
  },
  userInfo: {
    display: 'flex',
    alignItems: 'center',
    gap: '20px'
  },
  userName: {
    fontSize: '16px',
    fontWeight: 'bold'
  },
  logoutButton: {
    backgroundColor: '#e74c3c',
    color: 'white',
    border: 'none',
    padding: '8px 16px',
    borderRadius: '4px',
    cursor: 'pointer',
    fontSize: '14px',
    fontWeight: 'bold',
    transition: 'background-color 0.3s'
  },
  mainContainer: {
    display: 'flex',
    padding: '20px',
    gap: '20px',
    height: 'calc(100vh - 80px)'
  },
  sidebar: {
    width: '280px',
    backgroundColor: 'white',
    borderRadius: '8px',
    boxShadow: '0 2px 5px rgba(0,0,0,0.1)',
    padding: '20px',
    display: 'flex',
    flexDirection: 'column'
  },
  sidebarHeader: {
    borderBottom: '2px solid #3498db',
    paddingBottom: '10px',
    marginBottom: '20px'
  },
  sidebarTitle: {
    margin: 0,
    color: '#2c3e50',
    fontSize: '18px'
  },
  menuButton: {
    width: '100%',
    padding: '15px',
    marginBottom: '10px',
    border: 'none',
    borderRadius: '6px',
    backgroundColor: '#f8f9fa',
    color: '#2c3e50',
    fontSize: '16px',
    fontWeight: 'bold',
    textAlign: 'left',
    cursor: 'pointer',
    display: 'flex',
    alignItems: 'center',
    gap: '10px',
    transition: 'all 0.3s'
  },
  menuButtonActive: {
    backgroundColor: '#3498db',
    color: 'white',
    boxShadow: '0 2px 5px rgba(52,152,219,0.3)'
  },
  coordinadorInfo: {
    marginTop: 'auto',
    padding: '15px',
    backgroundColor: '#f8f9fa',
    borderRadius: '6px',
    border: '1px solid #e0e0e0'
  },
  coordinadorLabel: {
    margin: '0 0 5px 0',
    fontSize: '14px',
    color: '#7f8c8d'
  },
  coordinadorNombre: {
    margin: 0,
    fontSize: '16px',
    fontWeight: 'bold',
    color: '#2c3e50'
  },
  content: {
    flex: 1,
    backgroundColor: 'white',
    borderRadius: '8px',
    boxShadow: '0 2px 5px rgba(0,0,0,0.1)',
    padding: '25px',
    overflowY: 'auto'
  },
  formContainer: {
    maxWidth: '800px',
    margin: '0 auto'
  },
  formTitle: {
    color: '#2c3e50',
    borderBottom: '2px solid #3498db',
    paddingBottom: '10px',
    marginBottom: '25px'
  },
  form: {
    display: 'flex',
    flexDirection: 'column',
    gap: '20px'
  },
  formGroup: {
    display: 'flex',
    flexDirection: 'column',
    gap: '5px'
  },
  formRow: {
    display: 'flex',
    gap: '20px'
  },
  formGroupHalf: {
    flex: 1,
    display: 'flex',
    flexDirection: 'column',
    gap: '5px'
  },
  label: {
    fontSize: '14px',
    fontWeight: 'bold',
    color: '#34495e'
  },
  input: {
    padding: '10px',
    border: '1px solid #ddd',
    borderRadius: '4px',
    fontSize: '14px',
    transition: 'border-color 0.3s'
  },
  select: {
    padding: '10px',
    border: '1px solid #ddd',
    borderRadius: '4px',
    fontSize: '14px',
    backgroundColor: 'white'
  },
  textarea: {
    padding: '10px',
    border: '1px solid #ddd',
    borderRadius: '4px',
    fontSize: '14px',
    resize: 'vertical'
  },
  checkboxGroup: {
    display: 'flex',
    flexWrap: 'wrap',
    gap: '15px'
  },
  checkboxLabel: {
    display: 'flex',
    alignItems: 'center',
    gap: '5px',
    fontSize: '14px',
    cursor: 'pointer'
  },
  fileInput: {
    padding: '10px',
    border: '1px solid #ddd',
    borderRadius: '4px',
    fontSize: '14px',
    backgroundColor: 'white'
  },
  submitButton: {
    backgroundColor: '#3498db',
    color: 'white',
    padding: '15px',
    border: 'none',
    borderRadius: '4px',
    fontSize: '16px',
    fontWeight: 'bold',
    cursor: 'pointer',
    marginTop: '20px',
    transition: 'background-color 0.3s'
  }
};

// Componente para rutas protegidas
const ProtectedRoute = ({ children }) => {
  if (!authService.isAuthenticated()) {
    return <Navigate to="/login" />;
  }
  return children;
};

function App() {
  return (
    <Router>
      <Routes>
        <Route path="/login" element={<Login />} />
        <Route 
          path="/dashboard" 
          element={
            <ProtectedRoute>
              <Dashboard />
            </ProtectedRoute>
          } 
        />
        <Route path="/" element={<Navigate to="/login" />} />
      </Routes>
    </Router>
  );
}

export default App;
